12: /**
13:  * Handles case retrieval and follow-up merging.
14:  *
15:  * <pre>
16:  * GET  /cases/{caseId}            → return the latest stored case
17:  * POST /cases/{caseId}/follow-ups → merge follow-up, return annotated merged case
18:  * </pre>
19:  */
20: @RestController
21: @RequestMapping("/cases")
22: public class CaseController {
23: 
24:     private final CaseStore caseStore;
25:     private final MergeService mergeService;
26: 
27:     public CaseController(CaseStore caseStore, MergeService mergeService) {
28:         this.caseStore = caseStore;
29:         this.mergeService = mergeService;
30:     }
31: 
32:     /**
33:      * Returns the most recent stored version of the case.
34:      * Responds 404 if the caseId is not found.
35:      */
36:     @GetMapping("/{caseId}")
37:     public ResponseEntity<Case> getCase(@PathVariable String caseId) {
38:         Case c = caseStore.findById(caseId)
39:                 .orElseThrow(() -> new CaseNotFoundException(caseId));
40:         return ResponseEntity.ok(c);
41:     }
42: 
43:     /**
44:      * Merges the follow-up payload onto the stored case, persists the result,
45:      * and returns the fully annotated merged case.
46:      *
47:      * <p>Validations:
48:      * <ul>
49:      *   <li>400 — body caseId must match the URL path caseId</li>
50:      *   <li>400 — body must include a non-null {@code sections} map</li>
51:      *   <li>404 — caseId must exist in the store</li>
52:      * </ul>
53:      */
54:     @PostMapping("/{caseId}/follow-ups")
55:     public ResponseEntity<Case> postFollowUp(
56:             @PathVariable String caseId,
57:             @RequestBody Case followUp) {
58: 
59:         // Validate: URL caseId must match body case_id.
60:         if (followUp.caseId() == null || !caseId.equals(followUp.caseId())) {
61:             throw new ResponseStatusException(HttpStatus.BAD_REQUEST,
62:                     "URL caseId '" + caseId + "' does not match body case_id '"
63:                             + followUp.caseId() + "'");
64:         }
65: 
66:         // Validate: sections must be present (can be empty, but not null).
67:         if (followUp.sections() == null) {
68:             throw new ResponseStatusException(HttpStatus.BAD_REQUEST,
69:                     "Follow-up payload must include a 'sections' field");
70:         }
71: 
72:         Case stored = caseStore.findById(caseId)
73:                 .orElseThrow(() -> new CaseNotFoundException(caseId));
74: 
75:         Case merged = mergeService.merge(stored, followUp);
76:         caseStore.save(merged);
77: 
78:         return ResponseEntity.ok(merged);
79:     }
80: }
